"""Server-owned runtime for seeded finite probability experiments."""

from __future__ import annotations

import html
from typing import Any

from aetherviz_service.aetherviz.ir.probability_experiment.contract import compile_probability_experiment_ir


def assemble_probability_experiment_business_html(ir: dict[str, Any], plan: dict[str, Any], topic: str) -> str:
    compiled = compile_probability_experiment_ir(ir, plan)
    title = html.escape(str(plan.get("title") or topic or "随机试验"))
    goal = html.escape(str(plan.get("goal") or "比较理论概率与累计频率。"))
    observation = html.escape(str(ir.get("observation") or "试验次数增加时观察频率变化。"))
    animation = ir.get("animation") if isinstance(ir.get("animation"), dict) else {}
    variable = str(animation.get("variable") or "trials")
    variables = {
        str(item.get("name")): item
        for item in ((plan.get("interactive_spec") or {}).get("variables", []))
        if isinstance(item, dict) and item.get("name") and not item.get("computed")
    }
    meta = variables.get(variable, {})
    label = html.escape(str(meta.get("label") or "试验次数"))
    step = float(meta.get("step") or 1)
    return f'''<!doctype html><html lang="zh-CN"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>{title}</title><style>
.pe{{font-family:Inter,"PingFang SC",sans-serif;color:#263238;background:#fffaf2;padding:18px;min-height:100vh;box-sizing:border-box}}.pe h1{{margin:0;font-size:clamp(24px,4vw,38px)}}.pe-goal{{color:#6f6252}}.pe-layout{{display:grid;grid-template-columns:minmax(0,1fr) 280px;gap:16px}}.pe-stage,.pe-side{{background:#fff;border:1px solid #eadcc9;border-radius:18px;padding:14px}}#pe-svg{{width:100%;min-height:420px}}.pe-side strong{{font-size:28px;color:#b35c22}}.pe-controls{{display:flex;gap:10px;align-items:center;flex-wrap:wrap;margin-top:14px}}.pe-controls input{{flex:1;min-width:180px;accent-color:#d36f2d}}button,select{{border:0;border-radius:9px;padding:9px 13px;background:#f7e2cf;color:#82421d}}.axis{{stroke:#8e8174}}.grid{{stroke:#eee5dc}}.actual{{fill:none;stroke:#d36f2d;stroke-width:3}}.theory{{stroke:#3c7d72;stroke-width:2;stroke-dasharray:7 5}}.bar{{fill:#d98248}}.label{{font-size:12px;fill:#665a50}}@media(max-width:760px){{.pe-layout{{grid-template-columns:1fr}}}}
</style></head><body><main class="pe"><header data-region="learning-goal"><h1>{title}</h1><p class="pe-goal">{goal}</p></header><section class="pe-layout"><div class="pe-stage" id="aetherviz-stage"><svg id="pe-svg" data-role="main-visual" viewBox="0 0 760 440" role="img" aria-label="概率试验累计图"></svg></div><aside class="pe-side" data-region="caption"><h2>当前试验</h2><p><strong id="pe-count">0</strong> 次</p><div id="pe-readout"></div><p id="animation-caption">{observation}</p></aside></section><footer class="pe-controls control-panel" data-region="controls"><label for="pe-range">{label}</label><input id="pe-range" type="range" min="{float(animation.get("from", 1))}" max="{float(animation.get("to", 100))}" step="{step}" value="{float(animation.get("default", 10))}"><output id="pe-output"></output><select id="pe-view" aria-label="选择视图"></select><button id="play-animation">播放</button><button id="pause-animation">暂停</button><button id="reset-animation">重置</button><select id="pe-speed"><option value="0.5">0.5×</option><option value="1" selected>1×</option><option value="2">2×</option></select></footer></main><script id="probability-experiment-ir" type="application/json">{compiled}</script><script>
(()=>{{'use strict';const IR=JSON.parse(document.getElementById('probability-experiment-ir').textContent),svg=document.getElementById('pe-svg'),range=document.getElementById('pe-range'),output=document.getElementById('pe-output'),readout=document.getElementById('pe-readout'),caption=document.getElementById('animation-caption'),select=document.getElementById('pe-view');let controller,count=Math.round(Number(IR.animation.default)),view=IR.views[0].id;const NS='http://www.w3.org/2000/svg';
function rng(seed){{let value=seed%2147483647;return()=>{{value=value*16807%2147483647;return(value-1)/2147483646}}}}const random=rng(IR.seed),total=IR.outcomes.reduce((sum,item)=>sum+item.weight,0),samples=[];for(let i=0;i<Math.max(1,Math.ceil(IR.animation.to));i++){{let pick=random()*total,chosen=IR.outcomes[IR.outcomes.length-1].id;for(const item of IR.outcomes){{pick-=item.weight;if(pick<=0){{chosen=item.id;break}}}}samples.push(chosen)}}function node(name,attrs={{}}){{const el=document.createElementNS(NS,name);for(const [key,value] of Object.entries(attrs))el.setAttribute(key,String(value));return el}}function clear(){{while(svg.firstChild)svg.removeChild(svg.firstChild)}}function text(x,y,value,anchor='start'){{const el=node('text',{{x,y,class:'label','text-anchor':anchor}});el.textContent=value;svg.appendChild(el)}}function eventStats(event,n){{let hits=0,points=[];const set=new Set(event.outcomes);for(let i=0;i<n;i++){{if(set.has(samples[i]))hits++;points.push(hits/(i+1))}}return{{hits,points,frequency:n?hits/n:0,theory:IR.event_probabilities[event.id]}}}}
function axes(){{svg.appendChild(node('line',{{x1:58,y1:380,x2:730,y2:380,class:'axis'}}));svg.appendChild(node('line',{{x1:58,y1:30,x2:58,y2:380,class:'axis'}}));for(let i=0;i<=4;i++){{const y=380-i*87.5;svg.appendChild(node('line',{{x1:58,y1:y,x2:730,y2:y,class:'grid'}}));text(48,y+4,String(i/4),'end')}}}}
function renderFrequency(event){{axes();const stats=eventStats(event,count),width=672/Math.max(1,count),path=stats.points.map((value,index)=>(index?'L ':'M ')+(58+index*width)+' '+(380-value*350)).join(' ');svg.appendChild(node('path',{{d:path,class:'actual'}}));const ty=380-stats.theory*350;svg.appendChild(node('line',{{x1:58,y1:ty,x2:730,y2:ty,class:'theory'}}));text(720,ty-8,'理论概率 '+stats.theory.toFixed(3),'end')}}function renderSpace(){{const max=Math.max(...IR.outcomes.map(item=>item.weight)),w=620/IR.outcomes.length;IR.outcomes.forEach((item,index)=>{{const h=item.weight/max*280,x=70+index*w;svg.appendChild(node('rect',{{x:x+8,y:350-h,width:Math.max(10,w-16),height:h,class:'bar'}}));text(x+w/2,375,item.label,'middle');text(x+w/2,340-h,(item.weight/total).toFixed(2),'middle')}})}}function renderTree(){{const levels=Math.max(...IR.outcomes.map(item=>item.path.length)),seen=new Map();IR.outcomes.forEach((outcome,index)=>{{let px=50,py=220;outcome.path.forEach((label,level)=>{{const key=outcome.path.slice(0,level+1).join(' / '),x=140+(580/levels)*level,y=55+index*(330/Math.max(1,IR.outcomes.length-1));if(!seen.has(key)){{svg.appendChild(node('line',{{x1:px,y1:py,x2:x,y2:y,class:'axis'}}));svg.appendChild(node('circle',{{cx:x,cy:y,r:5,fill:'#d36f2d'}}));text(x+8,y-7,label);seen.set(key,{{x,y}})}}const point=seen.get(key);px=point.x;py=point.y}})}})}}
function render(){{clear();const current=IR.views.find(item=>item.id===view)||IR.views[0],event=IR.events.find(item=>item.id===current.event)||IR.events[0];if(current.type==='frequency_chart')renderFrequency(event);else if(current.type==='probability_tree')renderTree();else renderSpace();const stats=IR.events.map(item=>[item,eventStats(item,count)]);readout.innerHTML='';stats.forEach(([item,value])=>{{const p=document.createElement('p');p.textContent=item.label+'：'+value.hits+'/'+count+' = '+value.frequency.toFixed(3)+'（理论 '+value.theory.toFixed(3)+'）';readout.appendChild(p)}});document.getElementById('pe-count').textContent=String(count);range.value=String(count);output.value=String(count);caption.textContent=IR.observation+' 随机种子：'+IR.seed}}function setProgress(progress){{count=Math.max(1,Math.round(IR.animation.from+(IR.animation.to-IR.animation.from)*Math.max(0,Math.min(1,progress))));render()}}function play(){{controller.play()}}function pause(){{controller.pause()}}function reset(){{controller.reset();count=Math.round(IR.animation.default);render()}}function setSpeed(value){{controller.setSpeed(Math.max(.25,Math.min(4,Number(value)||1)))}}function update(patch){{if(patch&&patch[IR.animation.variable]!=null)count=Math.max(1,Math.min(samples.length,Math.round(Number(patch[IR.animation.variable]))));if(patch&&patch.view)view=String(patch.view);if(patch&&patch.speed!=null)setSpeed(patch.speed);render()}}function getState(){{return{{[IR.animation.variable]:count,view,seed:IR.seed}}}}
try{{IR.views.forEach(item=>{{const option=document.createElement('option');option.value=item.id;option.textContent=item.title;select.appendChild(option)}});if(!window.AetherVizAnimationController)throw new Error('missing_animation_controller');controller=window.AetherVizAnimationController.create({{duration:Number(IR.animation.duration)||7,update:setProgress}});range.addEventListener('input',()=>{{pause();count=Math.round(Number(range.value));render()}});select.addEventListener('change',()=>{{view=select.value;render()}});document.getElementById('play-animation').addEventListener('click',play);document.getElementById('pause-animation').addEventListener('click',pause);document.getElementById('reset-animation').addEventListener('click',reset);document.getElementById('pe-speed').addEventListener('change',event=>setSpeed(event.target.value));window.AetherVizRuntime={{play,pause,reset,setSpeed,update,getState}};render();window.__AETHERVIZ_RUNTIME_READY__=true}}catch(error){{window.__AETHERVIZ_RUNTIME_ERROR__=String(error&&error.message||error);caption.textContent='课件初始化失败：'+window.__AETHERVIZ_RUNTIME_ERROR__}}
}})();</script></body></html>'''
